import{C as t,o as l,c as n,a5 as a,E as r}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"3. Leader, leader schedule, rotation","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/3-leaders.md","filePath":"module-1/3-leaders.md","lastUpdated":1780937944000}'),o={name:"module-1/3-leaders.md"},c=Object.assign(o,{setup(h){const e={id:"m1-3-leaders",title:"🧠 Mini-check: Leader, leader schedule",intro:"3 питання — leader rotation базові концепти.",questions:[{type:"mcq",q:"Що з цього вірно про leader schedule? (обери всі правильні)",options:["Leader schedule для epoch N+1 визначається на base stake snapshot у кінці epoch N","Schedule визначає хто буде leader для кожного slot всього epoch (заздалегідь, deterministically)","Validator з більшим stake отримує більше slots у schedule (proportional)","Якщо validator делінквент під час слоту що для нього призначений, інший validator перебирає цей slot live"],correct:[0,1,2],explanation:'#1, #2, #3 правильні: schedule deterministic від stake snapshot, заздалегідь обчислений, proportional до stake. #4 НЕПРАВИЛЬНО — schedule fixed, ніхто не "перебирає" delinquent slot, він просто стає skipped.'},{type:"command",q:"Як подивитись чи буде твій validator (identity DSDefivSL...) leader у наступних 20 slots? Напиши команду з filter.",accepts:["solana leader-schedule --url http://localhost:8899 | grep DSDefivSL | head -20","solana leader-schedule | grep DSDefivSL | head -20","sudo /home/solana/ag/bin/solana leader-schedule --url http://localhost:8899 | grep DSDefivSL | head -20"],ideal:"solana leader-schedule | grep DSDefivSL | head -20",explanation:'solana leader-schedule виводить пари "slot_number identity_pubkey" для всього поточного epoch. grep по prefix твоєї identity показує тільки твої slots. head -20 — перші 20 hits.'},{type:"explain",q:"Чому Solana використовує проактивне (announced upfront) leader schedule, а не reactive (хто був першим створити block — той leader)?",ideal:`Проактивне leader schedule дає кілька critical переваг:

1. Performance: validators ЗАЗДАЛЕГІДЬ знають хто буде leader, можуть готуватись (warm up TPU sockets, pre-prepare transactions для forward). Це дає 400ms slot time можливим.

2. Predictability: clients знають куди send transactions (forward to current/upcoming leader через TPU). Без schedule — flooding всього cluster кожним TX.

3. No collision: reactive (PoW-style) має race conditions de кілька leaders створюють block одночасно → fork. Schedule eliminates це.

4. Stake-weighted fairness: schedule гарантує що validator з X% stake отримує приблизно X% slots. Reactive не гарантує fairness, lucky validator може взяти більше.

Tradeoff: schedule визначається ДО epoch старту, тому stake changes у середині epoch не affect schedule до наступного boundary.`,explanation:"Ключове: performance + predictability + no collision + fairness. Якщо описала performance + predictability — основа є. Bonus за обговорення TPU forwarding або no-fork properties."}]};return(p,s)=>{const i=t("Quiz");return l(),n("div",null,[s[0]||(s[0]=a("",56)),r(i,{data:e}),s[1]||(s[1]=a("",6))])}}});export{k as __pageData,c as default};
